mapper.select:
SELECT FROM recipe r
ORDER BY r.view_count DESC, r.created_at DESC, r.recipe_id DESC ORDER BY avgRating DESC, reviewCount DESC, r.recipe_id DESC ORDER BY (r.cook_time IS NULL), r.cook_time ASC, r.recipe_id DESC ORDER BY r.created_at DESC, r.recipe_id DESC
LIMIT #{size} OFFSET #{offset}
